	deq = deque(list("рҹҸғвҖҚвҷӮрҹҸӢвҖҚвҷҖрҹӨёвҖҚвҷӮрҹҸғвҖҚвҷӮрҹҸӢвҖҚвҷҖрҹӨёвҖҚвҷӮрҹҸғвҖҚвҷӮрҹҸӢвҖҚвҷҖрҹӨёвҖҚвҷӮ"))
